@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun CruiseEditScreen(
    cruiseId: Long?,
    onNavigateUp: () -> Unit,
    onCruiseSaved: ((Long) -> Unit)? = null,
    viewModel: CruiseEditViewModel = hiltViewModel(),
) {
    val isNewCruise = cruiseId == null || cruiseId == 0L

    LaunchedEffect(cruiseId) {
        if (cruiseId != null && cruiseId != 0L) {
            viewModel.loadCruise(cruiseId)
        }
    }

    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    val snackbarHostState = remember { SnackbarHostState() }
    var showSailDatePicker by remember { mutableStateOf(false) }

    // Inline itinerary slots
    val slots = remember { mutableStateListOf<ItinerarySlot>() }
    var slotsInitialized by remember { mutableStateOf(false) }
    var focusSlotIndex by remember { mutableIntStateOf(-1) }
    var editingNotesSlotIndex by remember { mutableIntStateOf(-1) }

    // Initialize slots: for new cruise, populate defaults immediately;
    // for existing cruise, wait until loadCruise completes (loadedSlots in uiState)
    LaunchedEffect(Unit) {
        if (isNewCruise && !slotsInitialized) {
            val sailDate = uiState.sailDate
            slots.addAll(listOf(
                ItinerarySlot(dayNumber = 1, date = sailDate),
                ItinerarySlot(dayNumber = 2, date = sailDate.plusDays(1)),
                ItinerarySlot(dayNumber = 3, date = sailDate.plusDays(2)),
                ItinerarySlot(dayNumber = 4, date = sailDate.plusDays(3)),
            ))
            slotsInitialized = true
        }
    }
    LaunchedEffect(uiState.loadedSlots) {
        val loaded = uiState.loadedSlots
        if (loaded != null && !slotsInitialized) {
            slots.addAll(loaded)
            slotsInitialized = true
        }
    }

    fun renumberSlots() {
        val sailDate = uiState.sailDate
        for (i in slots.indices) {
            val newDay = i + 1
            val newDate = sailDate.plusDays(i.toLong())
            if (slots[i].dayNumber != newDay || slots[i].date != newDate) {
                slots[i] = slots[i].copy(dayNumber = newDay, date = newDate)
            }
        }
    }

    LaunchedEffect(uiState.isSaved) {
        if (uiState.isSaved) {
            val savedId = uiState.savedCruiseId
            if (isNewCruise && savedId != null && onCruiseSaved != null) {
                onCruiseSaved(savedId)
            } else {
                onNavigateUp()
            }
        }
    }

    LaunchedEffect(uiState.error) {
        uiState.error?.let { error ->
            snackbarHostState.showSnackbar(error)
            viewModel.clearError()
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(if (isNewCruise) "New Cruise" else "Edit Cruise") },
                navigationIcon = {
                    TextButton(onClick = onNavigateUp) {
                        Text("Cancel")
                    }
                },
            )
        },
        snackbarHost = { SnackbarHost(snackbarHostState) },
        bottomBar = {
            Button(
                onClick = { viewModel.saveFromSlots(slots.toList()) },
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(16.dp),
                enabled = !uiState.isLoading,
            ) {
                if (uiState.isLoading) {
                    CircularProgressIndicator()
                } else {
                    Text("Save Cruise")
                }
            }
        },
    ) { padding ->
        Column(
            modifier = Modifier
                .padding(padding)
                .verticalScroll(rememberScrollState())
                .padding(16.dp),
        ) {
            // Cruise name
            OutlinedTextField(
                value = uiState.name,
                onValueChange = viewModel::onNameChange,
                label = { Text("Cruise Name") },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
            )

            Spacer(modifier = Modifier.height(12.dp))

            // Cruise line dropdown
            var cruiseLineExpanded by remember { mutableStateOf(false) }
            val selectedCruiseLine = CruiseLine.entries.find { it.name == uiState.cruiseLine }
            ExposedDropdownMenuBox(
                expanded = cruiseLineExpanded,
                onExpandedChange = { cruiseLineExpanded = it },
            ) {
                OutlinedTextField(
                    value = selectedCruiseLine?.displayName ?: "",
                    onValueChange = {},
                    label = { Text("Cruise Line") },
                    modifier = Modifier
                        .fillMaxWidth()
                        .menuAnchor(MenuAnchorType.PrimaryNotEditable),
                    readOnly = true,
                    singleLine = true,
                    trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = cruiseLineExpanded) },
                    colors = ExposedDropdownMenuDefaults.outlinedTextFieldColors(),
                )
                ExposedDropdownMenu(
                    expanded = cruiseLineExpanded,
                    onDismissRequest = { cruiseLineExpanded = false },
                ) {
                    CruiseLine.entries.forEach { line ->
                        DropdownMenuItem(
                            text = { Text(line.displayName) },
                            onClick = {
                                viewModel.onCruiseLineChange(line.name)
                                cruiseLineExpanded = false
                            },
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(12.dp))

            // Ship name
            OutlinedTextField(
                value = uiState.shipName,
                onValueChange = viewModel::onShipNameChange,
                label = { Text("Ship Name") },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
            )

            Spacer(modifier = Modifier.height(12.dp))

            // Sail date
            OutlinedTextField(
                value = DATE_FORMAT.format(uiState.sailDate),
                onValueChange = {},
                label = { Text("Sail Date") },
                modifier = Modifier.fillMaxWidth(),
                readOnly = true,
                singleLine = true,
                interactionSource = remember { androidx.compose.foundation.interaction.MutableInteractionSource() }
                    .also { interactionSource ->
                        LaunchedEffect(interactionSource) {
                            interactionSource.interactions.collect { interaction ->
                                if (interaction is androidx.compose.foundation.interaction.PressInteraction.Release) {
                                    showSailDatePicker = true
                                }
                            }
                        }
                    },
            )

            // Itinerary section
            Spacer(modifier = Modifier.height(16.dp))
            HorizontalDivider()
            Spacer(modifier = Modifier.height(8.dp))
            Text(text = "Itinerary", style = MaterialTheme.typography.titleMedium)
            Spacer(modifier = Modifier.height(8.dp))

            // Inline itinerary editor
            slots.forEachIndexed { index, slot ->
                val isFirst = index == 0
                val isLast = index == slots.size - 1
                val label = when {
                    isFirst -> "Embark"
                    isLast -> "Debark"
                    else -> "Day ${slot.dayNumber}"
                }
                val placeholder = when {
                    isFirst -> "Embark port"
                    isLast -> "Same as embark"
                    else -> "Sea day"
                }

                InlineItineraryRow(
                    slot = slot,
                    label = label,
                    placeholder = placeholder,
                    canMoveUp = !isFirst && !isLast && index > 1,
                    canMoveDown = !isFirst && !isLast && index < slots.size - 2,
                    canRemove = !isFirst && !isLast && slots.size > 3,
                    autoFocus = index == focusSlotIndex,
                    hasNotes = slot.notes.isNotBlank(),
                    onSearchPorts = { query -> viewModel.searchLocalPorts(query) },
                    onSlotUpdated = { updated -> slots[index] = updated },
                    onMoveUp = {
                        val temp = slots[index]
                        slots[index] = slots[index - 1]
                        slots[index - 1] = temp
                        renumberSlots()
                    },
                    onMoveDown = {
                        val temp = slots[index]
                        slots[index] = slots[index + 1]
                        slots[index + 1] = temp
                        renumberSlots()
                    },
                    onRemove = {
                        slots.removeAt(index)
                        renumberSlots()
                    },
                    onFocused = { focusSlotIndex = -1 },
                    onEditNotes = { editingNotesSlotIndex = index },
                )

                // "+ Add Day" button between the last intermediate day and Debark
                if (!isLast && index == slots.size - 2) {
                    TextButton(
                        onClick = {
                            val insertAt = slots.size - 1
                            val newDay = slots.size
                            slots.add(
                                insertAt,
                                ItinerarySlot(dayNumber = newDay, date = uiState.sailDate.plusDays(newDay.toLong() - 1)),
                            )
                            renumberSlots()
                            focusSlotIndex = insertAt
                        },
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(start = 56.dp),
                    ) {
                        Text("+ Add Day")
                    }
                }
            }
        }
    }

    // Notes dialog for a slot
    if (editingNotesSlotIndex in slots.indices) {
        val slot = slots[editingNotesSlotIndex]
        // Build a temporary PortOfCall for the NotesDialog display
        val tempPort = org.jewzaam.cruiseweather.data.local.entity.PortOfCall(
            portName = slot.portQuery.ifBlank { "At Sea" },
            date = slot.date,
            type = org.jewzaam.cruiseweather.data.local.entity.PortType.PORT_OF_CALL,
            notes = slot.notes,
            cruiseId = uiState.cruiseId,
        )
        NotesDialog(
            port = tempPort,
            sailDate = uiState.sailDate,
            onSave = { newNotes ->
                slots[editingNotesSlotIndex] = slot.copy(notes = newNotes)
                editingNotesSlotIndex = -1
            },
            onDismiss = { editingNotesSlotIndex = -1 },
        )
    }

    if (showSailDatePicker) {
        SailDatePickerDialog(
            initialDate = uiState.sailDate,
            onConfirm = { date ->
                viewModel.onSailDateChange(date)
                // Shift all slot dates
                val offset = java.time.temporal.ChronoUnit.DAYS.between(uiState.sailDate, date)
                for (i in slots.indices) {
                    slots[i] = slots[i].copy(date = slots[i].date.plusDays(offset))
                }
                showSailDatePicker = false
            },
            onDismiss = { showSailDatePicker = false },
        )
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
private fun InlineItineraryRow(
    slot: ItinerarySlot,
    label: String,
    placeholder: String,
    canMoveUp: Boolean,
    canMoveDown: Boolean,
    canRemove: Boolean,
    autoFocus: Boolean = false,
    hasNotes: Boolean = false,
    onSearchPorts: (String) -> List<CruisePort>,
    onSlotUpdated: (ItinerarySlot) -> Unit,
    onMoveUp: () -> Unit,
    onMoveDown: () -> Unit,
    onRemove: () -> Unit,
    onFocused: () -> Unit = {},
    onEditNotes: () -> Unit = {},
) {
    var expanded by remember { mutableStateOf(false) }
    var suggestions by remember { mutableStateOf<List<CruisePort>>(emptyList()) }
    var localQuery by remember(slot.portQuery) { mutableStateOf(slot.portQuery) }
    val focusRequester = remember { FocusRequester() }

    LaunchedEffect(autoFocus) {
        if (autoFocus) {
            focusRequester.requestFocus()
            onFocused()
        }
    }

    LaunchedEffect(localQuery) {
        if (localQuery.length < 2 || slot.resolvedPort != null) {
            suggestions = emptyList()
            expanded = false
            return@LaunchedEffect
        }
        delay(200)
        suggestions = onSearchPorts(localQuery)
        expanded = suggestions.isNotEmpty()
    }

    Row(
        verticalAlignment = Alignment.CenterVertically,
        modifier = Modifier
            .fillMaxWidth()
            .padding(vertical = 2.dp),
    ) {
        Text(
            text = label,
            style = MaterialTheme.typography.labelLarge,
            modifier = Modifier.width(56.dp),
        )

        ExposedDropdownMenuBox(
            expanded = expanded && suggestions.isNotEmpty(),
            onExpandedChange = {},
            modifier = Modifier.weight(1f),
        ) {
            OutlinedTextField(
                value = localQuery,
                onValueChange = { query ->
                    localQuery = query
                    onSlotUpdated(slot.copy(portQuery = query, resolvedPort = null))
                },
                placeholder = { Text(placeholder) },
                modifier = Modifier
                    .fillMaxWidth()
                    .menuAnchor(MenuAnchorType.PrimaryEditable)
                    .focusRequester(focusRequester),
                singleLine = true,
                textStyle = MaterialTheme.typography.bodyMedium,
            )
            ExposedDropdownMenu(
                expanded = expanded && suggestions.isNotEmpty(),
                onDismissRequest = { expanded = false },
            ) {
                suggestions.forEach { port ->
                    DropdownMenuItem(
                        text = { Text(port.displayName) },
                        onClick = {
                            onSlotUpdated(slot.copy(portQuery = port.displayName, resolvedPort = port))
                            expanded = false
                            suggestions = emptyList()
                        },
                    )
                }
            }
        }

        // Notes indicator
        TextButton(
            onClick = onEditNotes,
            modifier = Modifier.size(36.dp),
        ) {
            Text(
                text = if (hasNotes) "\uD83D\uDCDD" else "\u270E",
                style = MaterialTheme.typography.labelSmall,
            )
        }

        // Reorder and remove buttons
        if (canMoveUp) {
            IconButton(onClick = onMoveUp, modifier = Modifier.size(28.dp)) {
                Icon(Icons.Default.KeyboardArrowUp, contentDescription = "Move up", modifier = Modifier.size(18.dp))
            }
        } else if (canMoveDown || canRemove) {
            Spacer(modifier = Modifier.width(28.dp))
        }

        if (canMoveDown) {
            IconButton(onClick = onMoveDown, modifier = Modifier.size(28.dp)) {
                Icon(Icons.Default.KeyboardArrowDown, contentDescription = "Move down", modifier = Modifier.size(18.dp))
            }
        } else if (canMoveUp || canRemove) {
            Spacer(modifier = Modifier.width(28.dp))
        }

        if (canRemove) {
            IconButton(onClick = onRemove, modifier = Modifier.size(28.dp)) {
                Icon(
                    Icons.Default.Close, contentDescription = "Remove day",
                    tint = MaterialTheme.colorScheme.onSurfaceVariant,
                    modifier = Modifier.size(18.dp),
                )
            }
        } else if (canMoveUp || canMoveDown) {
            Spacer(modifier = Modifier.width(28.dp))
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
private fun SailDatePickerDialog(
    initialDate: LocalDate,
    onConfirm: (LocalDate) -> Unit,
    onDismiss: () -> Unit,
) {
    val millis = initialDate.atStartOfDay(ZoneOffset.UTC).toInstant().toEpochMilli()
    val datePickerState = rememberDatePickerState(initialSelectedDateMillis = millis)

    LaunchedEffect(datePickerState.selectedDateMillis) {
        val selectedMs = datePickerState.selectedDateMillis ?: return@LaunchedEffect
        if (selectedMs != millis) {
            val date = Instant.ofEpochMilli(selectedMs).atZone(ZoneOffset.UTC).toLocalDate()
            onConfirm(date)
        }
    }

    DatePickerDialog(
        onDismissRequest = onDismiss,
        confirmButton = {},
        dismissButton = {
            TextButton(onClick = onDismiss) { Text("Cancel") }
        },
    ) {
        DatePicker(
            state = datePickerState,
            title = {
                Text(
                    text = "Select sail date",
                    modifier = Modifier.padding(start = 24.dp, top = 16.dp),
                )
            },
        )
    }
}
